code = """import pandas as pd
import re
import json

# --- Step 1: Process business data from MongoDB query (var_function-call-1999720751843663753) ---
# The variable locals()['var_function-call-1999720751843663753'] contains the dictionary output of the query_db tool.
full_db_response_dict_business = locals()['var_function-call-1999720751843663753']

# Extract the list of result strings from the 'query_db_response' key.
raw_result_list_business = full_db_response_dict_business['query_db_response']['results']

# The actual JSON string (containing the list of business dictionaries) is the first element of this list.
json_string_with_meta_business = raw_result_list_business[0]

# Use regex to extract only the JSON array part (starts with '[' and ends with ']')
json_array_match_business = re.search(r'\[.*\]', json_string_with_meta_business, re.DOTALL)

df_business_states = pd.DataFrame()
business_refs_sql_clause = ""

if json_array_match_business:
    pure_json_array_str_business = json_array_match_business.group(0)
    business_data_list = json.loads(pure_json_array_str_business)

    df_business = pd.DataFrame(business_data_list)

    # Function to extract the state abbreviation from the description field
    def extract_state(description):
        if isinstance(description, str):
            # Regex to find a two-letter uppercase abbreviation (state code) after a comma and optional space.
            match = re.search(r',\s*([A-Z]{2})(?:\s|$|,)', description)
            if match:
                return match.group(1)
        return None

    # Apply the function to create a new 'state' column in the DataFrame
    df_business['state'] = df_business['description'].apply(extract_state)

    # Filter out businesses where state could not be extracted
    df_business_wifi = df_business.dropna(subset=['state'])

    # Create a 'business_ref' column by replacing 'businessid_' prefix with 'businessref_'
    df_business_wifi['business_ref'] = df_business_wifi['business_id'].str.replace('businessid_', 'businessref_')

    # Select only the 'business_ref' and 'state' columns needed
    df_business_states = df_business_wifi[['business_ref', 'state']].copy()
    
    # Prepare the list of business_refs in SQL IN clause format
    business_refs_list = df_business_states['business_ref'].tolist()
    business_refs_sql_format = ', '.join([f"'{ref}'" for ref in business_refs_list])
    business_refs_sql_clause = f"({business_refs_sql_format})"

    # Convert the DataFrame to a JSON string for passing to next step
    df_business_states_json = df_business_states.to_json(orient='records')

    result = {
        'business_refs_sql_clause': business_refs_sql_clause,
        'df_business_states_json': df_business_states_json
    }
    print("__RESULT__:")
    print(json.dumps(result))
else:
    print("__RESULT__:")
    print(json.dumps({"error": "Failed to extract JSON array for business data from MongoDB query." + json_string_with_meta_business}))
    exit()"""

